import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import Modal from "../components/Modal";
import { logout } from "../authReducer";

function Admin() {
  const [users, setUsers] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [userToBan, setUserToBan] = useState(null);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();

  useEffect(() => {
    fetch("http://localhost:3001/users")
      .then((res) => res.json())
      .then((data) => setUsers(data));
  }, []);

  async function handleBan(userId, isBanned) {
    try {
      const response = await fetch(`http://localhost:3001/users/${userId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ isBanned: !isBanned }),
      });

      if (response.ok) {
        setUsers(
          users.map((u) =>
            u.id === userId ? { ...u, isBanned: !isBanned } : u
          )
        );
        toast.success(
          !isBanned
            ? "Пользователь заблокирован!"
            : "Пользователь разблокирован!"
        );
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId,
            message: !isBanned
              ? "Ваш аккаунт заблокирован."
              : "Ваш аккаунт разблокирован.",
            createdAt: new Date().toISOString(),
          }),
        });
        if (userId === user.id && isBanned === false) {
          dispatch(logout());
        }
      } else {
        toast.error("Не удалось изменить статус пользователя");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при изменении статуса");
    }
    setIsModalOpen(false);
  }

  function openModal(userId, isBanned) {
    setUserToBan({ id: userId, isBanned });
    setIsModalOpen(true);
  }

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Админ-панель</h1>
      <h3>Управление пользователями</h3>
      <table className="table table-striped">
        <thead>
          <tr>
            <th>Имя</th>
            <th>Email</th>
            <th>Роль</th>
            <th>Класс</th>
            <th>Статус</th>
            <th>Действия</th>
          </tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.name}</td>
              <td>{u.email}</td>
              <td>{u.role}</td>
              <td>{u.classId || "—"}</td>
              <td>{u.isBanned ? "Заблокирован" : "Активен"}</td>
              <td>
                <button
                  onClick={() => openModal(u.id, u.isBanned)}
                  className={`btn btn-sm ${
                    u.isBanned ? "btn-success" : "btn-danger"
                  }`}
                  disabled={u.id === user.id && u.isBanned}
                >
                  {u.isBanned ? "Разблокировать" : "Заблокировать"}
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={() => handleBan(userToBan.id, userToBan.isBanned)}
        message={`Вы уверены, что хотите ${
          userToBan?.isBanned ? "разблокировать" : "заблокировать"
        } этого пользователя?`}
      />
    </div>
  );
}

export default Admin;
